export default async function handler(req, res) {
  // Allow GET for browser seeding
  const sql = neon(process.env.DATABASE_URL);

  await sql`
    CREATE TABLE IF NOT EXISTS sb_spices (
      id INTEGER PRIMARY KEY,
      name TEXT NOT NULL,
      also_known_as TEXT,
      category TEXT,
      origin TEXT,
      heat TEXT,
      flavor_profile TEXT,
      botanical TEXT,
      uses TEXT DEFAULT '[]',
      pairings TEXT DEFAULT '[]',
      description_en TEXT,
      description_no TEXT
    )
  `;

  let inserted = 0;
  for (const s of SPICES) {
    await sql`
      INSERT INTO sb_spices (id, name, also_known_as, category, origin, heat, flavor_profile, botanical, uses, pairings, description_en, description_no)
      VALUES (${s.id}, ${s.name}, ${s.also_known_as || null}, ${s.category}, ${s.origin}, ${s.heat}, ${s.flavor_profile}, ${s.botanical || null}, ${JSON.stringify(s.uses || [])}, ${JSON.stringify(s.pairings || [])}, ${s.description_en}, ${s.description_no})
      ON CONFLICT (id) DO UPDATE SET
        name = EXCLUDED.name, also_known_as = EXCLUDED.also_known_as,
        category = EXCLUDED.category, origin = EXCLUDED.origin,
        heat = EXCLUDED.heat, flavor_profile = EXCLUDED.flavor_profile,
        botanical = EXCLUDED.botanical, uses = EXCLUDED.uses,
        pairings = EXCLUDED.pairings,
        description_en = EXCLUDED.description_en, description_no = EXCLUDED.description_no
    `;
    inserted++;
  }

  return res.status(200).json({ ok: true, inserted, message: `Seeded ${inserted} spices.` });
}
